-- Migration: Add university intelligence and coordinates columns
-- Date: 2026-03-21

-- Add new columns for intelligence data
ALTER TABLE universities
ADD COLUMN IF NOT EXISTS latitude DECIMAL(9,6),
ADD COLUMN IF NOT EXISTS longitude DECIMAL(9,6),
ADD COLUMN IF NOT EXISTS fit_score INTEGER,
ADD COLUMN IF NOT EXISTS fit_breakdown JSONB,
ADD COLUMN IF NOT EXISTS tags TEXT[],
ADD COLUMN IF NOT EXISTS rationale TEXT,
ADD COLUMN IF NOT EXISTS tuition_band INTEGER CHECK (tuition_band BETWEEN 1 AND 4),
ADD COLUMN IF NOT EXISTS living_cost_band INTEGER CHECK (living_cost_band BETWEEN 1 AND 4),
ADD COLUMN IF NOT EXISTS employability_score INTEGER,
ADD COLUMN IF NOT EXISTS international_support_score INTEGER,
ADD COLUMN IF NOT EXISTS scholarship_signal TEXT CHECK (scholarship_signal IN ('high', 'medium', 'low', 'none')),
ADD COLUMN IF NOT EXISTS hero_image_url TEXT;

-- Create index for spatial queries (if needed later)
CREATE INDEX IF NOT EXISTS idx_universities_coordinates ON universities (latitude, longitude);
CREATE INDEX IF NOT EXISTS idx_universities_fit_score ON universities (fit_score DESC);

