ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  logo_url = EXCLUDED.logo_url,
  ranking_uk = EXCLUDED.ranking_uk,
  ranking_global = EXCLUDED.ranking_global,
  location = EXCLUDED.location,
  city = EXCLUDED.city,
  description = EXCLUDED.description,
  website = EXCLUDED.website,
  is_russell_group = EXCLUDED.is_russell_group,
  latitude = EXCLUDED.latitude,
  longitude = EXCLUDED.longitude,
  fit_score = EXCLUDED.fit_score,
  fit_breakdown = EXCLUDED.fit_breakdown,
  tags = EXCLUDED.tags,
  rationale = EXCLUDED.rationale,
  tuition_band = EXCLUDED.tuition_band,
  living_cost_band = EXCLUDED.living_cost_band,
  employability_score = EXCLUDED.employability_score,
  international_support_score = EXCLUDED.international_support_score,
  scholarship_signal = EXCLUDED.scholarship_signal,
  hero_image_url = EXCLUDED.hero_image_url;

-- Comments for documentation
COMMENT ON COLUMN universities.latitude IS 'Geographic latitude coordinate';
COMMENT ON COLUMN universities.longitude IS 'Geographic longitude coordinate';
COMMENT ON COLUMN universities.fit_score IS 'Overall fit score for the user (0-100)';
COMMENT ON COLUMN universities.fit_breakdown IS 'JSON object with fit scores by category: academic, budget, location, career, lifestyle';
COMMENT ON COLUMN universities.tags IS 'Array of tags describing university strengths';
COMMENT ON COLUMN universities.rationale IS 'Personalized explanation of why this university is recommended';
COMMENT ON COLUMN universities.tuition_band IS 'Tuition cost band (1=£10-15k, 2=£15-22k, 3=£22-30k, 4=£30k+)';
COMMENT ON COLUMN universities.living_cost_band IS 'Living cost band (1=£600-800/mo, 2=£800-1100/mo, 3=£1100-1500/mo, 4=£1500+/mo)';
COMMENT ON COLUMN universities.employability_score IS 'Graduate employability score (0-100)';
COMMENT ON COLUMN universities.international_support_score IS 'International student support score (0-100)';
COMMENT ON COLUMN universities.scholarship_signal IS 'Availability of scholarships (high, medium, low, none)';
COMMENT ON COLUMN universities.hero_image_url IS 'Hero image URL for the university card';
